import { SeedServerSentEventsResumableClient } from "../../src/Client";
import { mockServerPool } from "../mock-server/MockServerPool";

describe("CompletionsClient", () => {
    test("stream", async () => {
        const server = mockServerPool.createServer();
        const client = new SeedServerSentEventsResumableClient({ maxRetries: 0, environment: server.baseUrl });
        const rawRequestBody = { query: "foo" };
        const rawResponseBody =
            'event: completion\ndata: {"delta":"hello","tokens":1}\n\nevent: completion\ndata: {"delta":" world","tokens":2}\n\n';

        server
            .mockEndpoint()
            .post("/stream")
            .jsonBody(rawRequestBody)
            .respondWith()
            .statusCode(200)
            .sseBody(rawResponseBody)
            .build();

        const response = await client.completions.stream({
            query: "foo",
        });
        const events: unknown[] = [];
        for await (const event of response) {
            events.push(event);
        }
        expect(events).toEqual([
            {
                delta: "hello",
                tokens: 1,
            },
            {
                delta: " world",
                tokens: 2,
            },
        ]);
    });

    test("streamNonResumable", async () => {
        const server = mockServerPool.createServer();
        const client = new SeedServerSentEventsResumableClient({ maxRetries: 0, environment: server.baseUrl });
        const rawRequestBody = { query: "bar" };
        const rawResponseBody = 'event: completion\ndata: {"delta":"no resume","tokens":1}\n\n';

        server
            .mockEndpoint()
            .post("/stream-non-resumable")
            .jsonBody(rawRequestBody)
            .respondWith()
            .statusCode(200)
            .sseBody(rawResponseBody)
            .build();

        const response = await client.completions.streamNonResumable({
            query: "bar",
        });
        const events: unknown[] = [];
        for await (const event of response) {
            events.push(event);
        }
        expect(events).toEqual([
            {
                delta: "no resume",
                tokens: 1,
            },
        ]);
    });
});
